#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long a,b,c; scanf("%lld %lld %lld",&a,&b,&c);
        if(a!=b && b!=c && a!=c) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

