#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        a = int(next(it)); b = int(next(it)); c = int(next(it))
        out.append("YES" if a!=b and b!=c and a!=c else "NO")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

